When an audio device is disconnected, the SDL_mixer library will automatically handle switching the audio output to a fallback device, if available. However, when the audio device is reconnected, you need to reopen the audio device to ensure the SDL_mixer library uses the newly connected device for audio playback.

Here's an example of how you can handle reconnecting an audio device when it is connected again:

```cpp
#include <iostream>
#include <SDL2/SDL.h>
#include <SDL2/SDL_mixer.h>

// Declare global variables for the audio device and audio format
int audioDevice = -1;
SDL_AudioSpec audioFormat;

// Reopen audio device
bool reopenAudioDevice() {
    if (audioDevice != -1) {
        // Close the current audio device
        Mix_CloseAudioDevice(audioDevice);
    }

    // Reopen the audio device
    audioDevice = Mix_OpenAudioDevice(NULL, 0, &audioFormat, NULL, 0);
    if (audioDevice == 0) {
        std::cerr << "Failed to reopen audio device: " << Mix_GetError() << std::endl;
        return false;
    }

    return true;
}

// Handle audio device connection/disconnection events
void handleAudioDeviceEvent(const SDL_Event& event) {
    if (event.type == SDL_AUDIODEVICEADDED) {
        std::cout << "Audio Device Added: " << event.adevice.which << std::endl;
        reopenAudioDevice();
    } else if (event.type == SDL_AUDIODEVICEREMOVED) {
        std::cout << "Audio Device Removed: " << event.adevice.which << std::endl;
        reopenAudioDevice();
    }
}

int main() {
    // Initialize SDL
    if (SDL_Init(SDL_INIT_AUDIO) != 0) {
        std::cerr << "Failed to initialize SDL: " << SDL_GetError() << std::endl;
        return 1;
    }

    // Initialize SDL_mixer
    if (Mix_OpenAudio(44100, MIX_DEFAULT_FORMAT, 2, 2048) < 0) {
        std::cerr << "Failed to initialize SDL_mixer: " << Mix_GetError() << std::endl;
        return 1;
    }

    // Get the current audio device and format
    audioDevice = Mix_GetDeviceID(); // Get the currently opened audio device ID
    Mix_QuerySpec(&audioFormat.freq, &audioFormat.format, &audioFormat.channels);

    // Register the audio device event type
    SDL_EventState(SDL_AUDIODEVICEADDED, SDL_ENABLE);
    SDL_EventState(SDL_AUDIODEVICEREMOVED, SDL_ENABLE);

    // Main loop
    bool quit = false;
    while (!quit) {
        SDL_Event event;
        while (SDL_PollEvent(&event)) {
            if (event.type == SDL_QUIT) {
                quit = true;
            } else if (event.type == SDL_AUDIODEVICEADDED ||
                       event.type == SDL_AUDIODEVICEREMOVED) {
                handleAudioDeviceEvent(event);
            }
        }

        // Your game/application logic here...
        SDL_Delay(16); // Delay to control CPU usage
    }

    // Close the audio device and SDL_mixer
    Mix_CloseAudioDevice(audioDevice);
    Mix_Quit();

    // Quit SDL
    SDL_Quit();

    return 0;
}
```

