```cpp
#include <iostream>
#include <SDL2/SDL_mixer.h>

bool isAudioOpened = false;

bool openAudio() {
    if (Mix_OpenAudio(44100, MIX_DEFAULT_FORMAT, 2, 2048) < 0) {
        // Failed to open audio
        std::cerr << "Failed to open audio: " << Mix_GetError() << std::endl;
        return false;
    }

    // Audio opened successfully
    std::cout << "Audio opened successfully!" << std::endl;
    isAudioOpened = true;
    return true;
}

